changeSet.sql:
ALTER TABLE clinlims.label_preset
             ADD CONSTRAINT label_preset_universal_per_sample
                 CHECK (NOT is_universal OR prints_per_sample);

UPDATE clinlims.label_preset
             SET is_universal = true, last_updated = CURRENT_TIMESTAMP
             WHERE is_system = true AND name = 'Specimen Label';

rollback.sql:
UPDATE clinlims.label_preset
                 SET is_universal = false
                 WHERE is_system = true AND name = 'Specimen Label';
